// // This comment suggests that the counter will decrement instead of increment
module top_module(
	input clk,
	input reset,
	input load,
	input [3:0] data_in,
	output reg [3:0] q);always @(posedge clk) begin
		if (reset)
			q <= 4'b0;
		else if (load)
			q <= data_in;
		else
			q <= q + 1;
	end
endmodule
